const crypto = require('crypto');

const SECRET_KEY = 'mN4!pQs6JrYwV9';
const job = $input.first().json;

if (!job.player_id) {
  throw new Error('Missing player_id');
}

if (!job.server_id) {
  throw new Error(`Missing Kingdom/server_id for player ${job.player_id}`);
}

if (!job.gift_code) {
  throw new Error('Missing gift_code');
}

const redeemParams = {
  fid: String(job.player_id),
  kid: String(job.server_id),
  cdk: String(job.gift_code),
  time: String(Math.floor(Date.now() / 1000)),
};

const raw = Object.keys(redeemParams)
  .sort()
  .map((key) => `${key}=${encodeURIComponent(redeemParams[key])}`)
  .join('&');

const sign = crypto
  .createHash('md5')
  .update(raw + SECRET_KEY, 'utf8')
  .digest('hex');

return [{
  json: {
    ...job,
    redeem_form: {
      sign,
      ...redeemParams,
    },
    sign_raw: raw,
  },
}];

const job = $('Claim One Pending Job').first().json;
const http = $input.first().json;
const payload = http.body ?? http.data ?? http;

const code = Number(payload?.code ?? -1);
const errCode = Number(payload?.err_code ?? payload?.data?.err_code ?? -1);
const message = String(payload?.msg ?? 'Unknown response');

let status = 'failed';

if (code === 0 && errCode === 20000) {
  status = 'success';
} else if (
  errCode === 40008 ||
  message.trim().toUpperCase() === 'RECEIVED.'
) {
  status = 'success';
} else if ([40001, 40003, 40007].includes(errCode)) {
  status = 'already_redeemed';
} else if (errCode === 40002) {
  status = 'expired';
}

return [{
  json: {
    redemption_id: job.redemption_id,
    result_status: status,
    response_message: message,
    response_data: payload,
    http_status: http.statusCode ?? null,
    err_code: errCode,
  },
}];
